fn trusted_non_root_selected_group_empty_local_payload_still_requires_bridge() {
    let request = query::InternalQueryRequest::materialized(
        query::QueryOp::Tree,
        query::QueryScope {
            path: b"/nested".to_vec(),
            recursive: true,
            max_depth: Some(1),
            selected_group: Some("nfs2".to_string()),
        },
        Some(query::TreeQueryOptions {
            read_class: query::ReadClass::TrustedMaterialized,
        }),
    );
    let payload = rmp_serde::to_vec_named(&query::MaterializedQueryPayload::Tree(
        query::TreeGroupPayload {
            reliability: query::GroupReliability {
                reliable: false,
                unreliable_reason: Some(crate::shared_types::query::UnreliableReason::Unattested),
            },
            stability: query::TreeStability::not_evaluated(),
            root: query::TreePageRoot {
                path: b"/nested".to_vec(),
                size: 0,
                modified_time_us: 0,
                is_dir: true,
                exists: false,
                has_children: false,
            },
            entries: Vec::new(),
        },
    ))
    .expect("encode empty trusted subtree tree payload");
    let empty_local_event = Event::new(
        EventMetadata {
            origin_id: NodeId("nfs2".to_string()),
            timestamp_us: 1,
            logical_ts: None,
            correlation_id: Some(12),
            ingress_auth: None,
            trace: None,
        },
        Bytes::from(payload),
    );

    assert!(should_bridge_selected_group_sink_query(
        &request,
        &[empty_local_event],
        true,
    ));
}

#[test]
fn trusted_exact_file_selected_group_empty_local_payload_skips_bridge_for_recursive_request_shape()
{
    let request = query::InternalQueryRequest::materialized(
        query::QueryOp::Tree,
        query::QueryScope {
            path: b"/nested/child/deep.txt".to_vec(),
            recursive: true,
            max_depth: None,
            selected_group: Some("nfs2".to_string()),
        },
        Some(query::TreeQueryOptions {
            read_class: query::ReadClass::TrustedMaterialized,
        }),
    );
    let empty_event = selected_group_empty_materialized_reply(&request, Some(13))
        .expect("build empty reply")
        .expect("selected-group reply");

    assert!(
        !should_bridge_selected_group_sink_query(&request, &[empty_event], true),
        "trusted exact-file selected-group requests should not spend bridge budget once the local selected-group reply already proved the exact path missing"
    );
}

