#[test]
fn trusted_non_root_selected_group_empty_local_payload_emits_explicit_empty_reply_after_bridge_timeout_when_max_depth_limited()
 {
    let request = query::InternalQueryRequest::materialized(
        query::QueryOp::Tree,
        query::QueryScope {
            path: b"/nested".to_vec(),
            recursive: true,
            max_depth: Some(1),
            selected_group: Some("nfs3".to_string()),
        },
        Some(query::TreeQueryOptions {
            read_class: query::ReadClass::TrustedMaterialized,
        }),
    );
    let empty_event = selected_group_empty_materialized_reply(&request, Some(11))
        .expect("build empty reply")
        .expect("selected-group reply");

    let event = selected_group_empty_materialized_reply_after_bridge_failure(
        &request,
        &[empty_event],
        true,
        &CnxError::Timeout,
        Some(41),
    )
    .expect("bridge-failure reply");
    let event = event.expect("bridge timeout should still settle with an explicit reply");
    let payload = rmp_serde::from_slice::<MaterializedQueryPayload>(event.payload_bytes())
        .expect("decode selected-group reply payload");
    let MaterializedQueryPayload::Tree(payload) = payload else {
        panic!("expected tree payload");
    };

    assert_eq!(event.metadata().origin_id.0, "nfs3");
    assert_eq!(event.metadata().correlation_id, Some(41));
    assert!(!payload.root.exists);
    assert_eq!(payload.root.path, b"/nested".to_vec());
    assert!(
        payload.entries.is_empty(),
        "explicit empty selected-group subtree reply must not include entries: {payload:?}"
    );
}

