#[tokio::test]
async fn source_reconcile_retains_latest_deactivate_directive_after_reset() {
    let app = FSMetaApp::new(
        FSMetaConfig {
            source: local_source_config(),
            ..FSMetaConfig::default()
        },
        NodeId("single-app-node".into()),
    )
    .expect("init app");

    let route_key = format!("{}.stream", ROUTE_KEY_SOURCE_ROOTS_CONTROL);
    let route_id = (
        execution_units::SOURCE_RUNTIME_UNIT_ID.to_string(),
        route_key.clone(),
    );

    let (initial_source_signals, _, _) =
        split_app_control_signals(&[activate_envelope_with_route_key_and_scope_rows(
            execution_units::SOURCE_RUNTIME_UNIT_ID,
            route_key.clone(),
            &[("root-a", &["single-app-node::root-1"])],
            2,
        )])
        .expect("split initial source activate");
    app.record_retained_source_control_state(&initial_source_signals)
        .await;
    app.source_state_replay_required
        .store(true, Ordering::Release);

    let (deactivate_source_signals, _, _) =
        split_app_control_signals(&[deactivate_envelope_with_route_key(
            execution_units::SOURCE_RUNTIME_UNIT_ID,
            route_key.clone(),
            3,
        )])
        .expect("split source deactivate");
    app.record_retained_source_control_state(&deactivate_source_signals)
        .await;

    let replayed = app.source_signals_with_replay(&[]).await;
    match replayed.iter().find(|signal| match signal {
        SourceControlSignal::Activate {
            unit, route_key, ..
        }
        | SourceControlSignal::Deactivate {
            unit, route_key, ..
        } => unit.unit_id() == execution_units::SOURCE_RUNTIME_UNIT_ID && route_key == &route_id.1,
        SourceControlSignal::Tick { .. }
        | SourceControlSignal::RuntimeHostGrantChange { .. }
        | SourceControlSignal::ManualRescan { .. }
        | SourceControlSignal::Passthrough(_) => false,
    }) {
        Some(SourceControlSignal::Deactivate { generation, .. }) => assert_eq!(
            *generation, 3,
            "desired-state reconcile must retain the latest deactivate directive for the route after reset"
        ),
        other => panic!("expected replayed source deactivate for {route_id:?}, got {other:?}"),
    }
}

#[tokio::test]
async fn generation_cutover_restart_deferred_cleanup_tail_fail_closes_before_replay_budget_exhaustion_when_replayed_source_batch_hits_retryable_resets()
 {
    use std::collections::VecDeque;

    let app = FSMetaApp::new(
        FSMetaConfig {
            source: local_source_config(),
            ..FSMetaConfig::default()
        },
        NodeId("single-app-node".into()),
    )
    .expect("init app");

    let seed_envelopes = vec![
        host_object_grants_changed_rows_envelope(
            1,
            &[(
                "single-app-node::root-1",
                "single-app-node",
                "127.0.0.1",
                "/mnt/root-1",
                "/tmp/root-1",
                true,
            )],
        ),
        activate_envelope_with_route_key_and_scope_rows(
            execution_units::SOURCE_RUNTIME_UNIT_ID,
            format!("{}.stream", ROUTE_KEY_SOURCE_ROOTS_CONTROL),
            &[("root-a", &["single-app-node::root-1"])],
            2,
        ),
        activate_envelope_with_route_key_and_scope_rows(
            execution_units::SOURCE_RUNTIME_UNIT_ID,
            format!("{}.stream", ROUTE_KEY_SOURCE_RESCAN_CONTROL),
            &[("root-a", &["single-app-node::root-1"])],
            2,
        ),
        activate_envelope_with_route_key_and_scope_rows(
            execution_units::SOURCE_RUNTIME_UNIT_ID,
            format!("{}.req", ROUTE_KEY_SOURCE_RESCAN_INTERNAL),
            &[("root-a", &["single-app-node::root-1"])],
            2,
        ),
        activate_envelope_with_route_key_and_scope_rows(
            execution_units::SOURCE_SCAN_RUNTIME_UNIT_ID,
            format!("{}.req", ROUTE_KEY_SOURCE_RESCAN_INTERNAL),
            &[("root-a", &["single-app-node::root-1"])],
            2,
        ),
    ];
    let (seed_source_signals, _, _) =
        split_app_control_signals(&seed_envelopes).expect("split seeded source replay state");
    app.record_retained_source_control_state(&seed_source_signals)
        .await;
    app.source_state_replay_required
        .store(true, std::sync::atomic::Ordering::Release);
    app.control_initialized
        .store(true, std::sync::atomic::Ordering::Release);

    let cleanup_envelopes = vec![
        deactivate_envelope_with_route_key_reason_and_lease(
            execution_units::SOURCE_RUNTIME_UNIT_ID,
            format!("{}.stream", ROUTE_KEY_SOURCE_ROOTS_CONTROL),
            3,
            "restart_deferred_retire_pending",
            7,
            11,
            22,
        ),
        deactivate_envelope_with_route_key_reason_and_lease(
            execution_units::SOURCE_RUNTIME_UNIT_ID,
            format!("{}.stream", ROUTE_KEY_SOURCE_RESCAN_CONTROL),
            3,
            "restart_deferred_retire_pending",
            7,
            11,
            22,
        ),
        deactivate_envelope_with_route_key_reason_and_lease(
            execution_units::SOURCE_RUNTIME_UNIT_ID,
            format!("{}.req", ROUTE_KEY_SOURCE_RESCAN_INTERNAL),
            3,
            "restart_deferred_retire_pending",
            7,
            11,
            22,
        ),
        deactivate_envelope_with_route_key_reason_and_lease(
            execution_units::SOURCE_SCAN_RUNTIME_UNIT_ID,
            format!("{}.req", ROUTE_KEY_SOURCE_RESCAN_INTERNAL),
            3,
            "restart_deferred_retire_pending",
            7,
            11,
            22,
        ),
    ];
    let (cleanup_source_signals, _, _) =
        split_app_control_signals(&cleanup_envelopes).expect("split cleanup-tail source signals");

    let _source_apply_error_reset = SourceApplyErrorQueueHookReset;
    install_source_apply_error_queue_hook(SourceApplyErrorQueueHook {
        errs: std::iter::repeat_with(|| CnxError::Timeout)
            .take(256)
            .collect::<VecDeque<_>>(),
    });

    tokio::time::timeout(
        Duration::from_millis(900),
        app.apply_source_signals_with_recovery(&cleanup_source_signals, true, true),
    )
    .await
    .expect(
        "generation-cutover restart_deferred cleanup tails must fail-close before replay/reinitialize loops exhaust caller-observed budget",
    )
    .expect(
        "generation-cutover restart_deferred cleanup tails should fail-close on repeated retryable replay resets instead of bubbling timeout",
    );

    assert!(
        !app.control_initialized(),
        "fail-closed cleanup-tail replay should leave runtime uninitialized for follow-up recovery"
    );
}

