#[test]
fn facade_route_key_matches_dual_owned_internal_query_routes_for_both_units() {
    let sink_query_proxy = format!("{}.req", ROUTE_KEY_SINK_QUERY_PROXY);
    let sink_status = format!("{}.req", ROUTE_KEY_SINK_STATUS_INTERNAL);
    let source_status = format!("{}.req", ROUTE_KEY_SOURCE_STATUS_INTERNAL);
    let source_find = format!("{}.req", ROUTE_KEY_SOURCE_FIND_INTERNAL);

    for route in [
        sink_query_proxy.as_str(),
        sink_status.as_str(),
        source_status.as_str(),
        source_find.as_str(),
    ] {
        assert!(facade_route_key_matches(FacadeRuntimeUnit::Query, route));
        assert!(facade_route_key_matches(
            FacadeRuntimeUnit::QueryPeer,
            route
        ));
    }
    assert!(!facade_route_key_matches(
        FacadeRuntimeUnit::QueryPeer,
        &format!("{}.req", ROUTE_KEY_QUERY)
    ));
}

#[tokio::test]
async fn peer_only_internal_query_routes_mirror_query_lane_activation_after_turnover() {
    let app = FSMetaApp::with_boundaries(
        FSMetaConfig::default(),
        NodeId("node-c-29776147311333818169819137".into()),
        Some(Arc::new(NoopBoundary)),
    )
    .expect("init app");

    let route_scopes = [RuntimeBoundScope {
        scope_id: "nfs1".to_string(),
        resource_ids: vec!["listener-a".to_string()],
    }];
    let source_status_route = format!("{}.req", ROUTE_KEY_SOURCE_STATUS_INTERNAL);
    let sink_query_proxy_route = format!("{}.req", ROUTE_KEY_SINK_QUERY_PROXY);

    app.apply_facade_activate(
        FacadeRuntimeUnit::QueryPeer,
        &source_status_route,
        2,
        &route_scopes,
    )
    .await
    .expect("activate query-peer source-status route");
    app.apply_facade_activate(
        FacadeRuntimeUnit::QueryPeer,
        &sink_query_proxy_route,
        2,
        &route_scopes,
    )
    .await
    .expect("activate query-peer sink-query-proxy route");

    let query_peer_state = app
        .facade_gate
        .unit_state(execution_units::QUERY_PEER_RUNTIME_UNIT_ID)
        .expect("query-peer state")
        .expect("query-peer unit should exist");
    assert!(query_peer_state.0, "query-peer lane must be active");

    let query_state = app
        .facade_gate
        .unit_state(execution_units::QUERY_RUNTIME_UNIT_ID)
        .expect("query state")
        .expect("query unit should be mirrored for peer-only internal query routes");
    assert!(
        query_state.0,
        "peer-only internal query routes must also activate the query lane for delivery continuity"
    );
    let scope_ids = query_state
        .1
        .into_iter()
        .map(|scope| scope.scope_id)
        .collect::<std::collections::BTreeSet<_>>();
    assert_eq!(
        scope_ids,
        std::collections::BTreeSet::from(["nfs1".to_string()])
    );
}

#[tokio::test]
async fn mark_control_uninitialized_clears_source_find_route_for_both_query_lanes() {
    let app = FSMetaApp::with_boundaries(
        FSMetaConfig::default(),
        NodeId("node-c-29776147311333818169819137".into()),
        Some(Arc::new(NoopBoundary)),
    )
    .expect("init app");

    let route_scopes = [RuntimeBoundScope {
        scope_id: "nfs1".to_string(),
        resource_ids: vec!["listener-a".to_string()],
    }];
    let source_find_route = format!("{}.req", ROUTE_KEY_SOURCE_FIND_INTERNAL);
    let source_status_route = format!("{}.req", ROUTE_KEY_SOURCE_STATUS_INTERNAL);

    app.apply_facade_activate(
        FacadeRuntimeUnit::QueryPeer,
        &source_find_route,
        2,
        &route_scopes,
    )
    .await
    .expect("activate query-peer source-find route");
    app.apply_facade_activate(
        FacadeRuntimeUnit::QueryPeer,
        &source_status_route,
        2,
        &route_scopes,
    )
    .await
    .expect("activate query-peer source-status route");

    assert!(
        app.facade_gate
            .route_active(
                execution_units::QUERY_PEER_RUNTIME_UNIT_ID,
                &source_find_route
            )
            .expect("query-peer source-find active before failure"),
        "query-peer source-find route should be active before forced uninitialized cleanup"
    );
    assert!(
        app.facade_gate
            .route_active(execution_units::QUERY_RUNTIME_UNIT_ID, &source_find_route)
            .expect("mirrored query source-find active before failure"),
        "mirrored query source-find route should be active before forced uninitialized cleanup"
    );

    app.mark_control_uninitialized_after_failure().await;

    assert!(
        !app.facade_gate
            .route_active(
                execution_units::QUERY_PEER_RUNTIME_UNIT_ID,
                &source_find_route
            )
            .expect("query-peer source-find active after failure"),
        "query-peer source-find route must be withdrawn when runtime control becomes uninitialized"
    );
    assert!(
        !app.facade_gate
            .route_active(execution_units::QUERY_RUNTIME_UNIT_ID, &source_find_route)
            .expect("mirrored query source-find active after failure"),
        "mirrored query source-find route must also withdraw when runtime control becomes uninitialized"
    );
    assert!(
        !app.facade_gate
            .route_active(
                execution_units::QUERY_PEER_RUNTIME_UNIT_ID,
                &source_status_route
            )
            .expect("query-peer source-status active after failure"),
        "query-peer source-status route should still withdraw on uninitialized cleanup"
    );
}

